const items = $input.all();

const stats = {
    totalPartners: items.length,
    active: 0,
    completed: 0,
    overdue: 0,
    certificatesIssued: 0,
    pendingCertificates: 0,
    remindersSent: 0,
    escalations: 0,
    trainingPrograms: {}
};

for (const item of items) {

    const props = item.json.properties;

    const status =
        props["Training Status"]?.status?.name ?? "";

    const certificate =
        props["Certificate Issued"]?.checkbox ?? false;

    const reminder =
        props["Reminder Count"]?.number ?? 0;

    const escalation =
        props["Needs Manager Escalation"]?.checkbox ?? false;

    const program =
        props["Training Program"]?.select?.name ??
        "Unknown";

    if(status==="Completed")
        stats.completed++;

    else if(status==="Overdue")
        stats.overdue++;

    else
        stats.active++;

    if(certificate)
        stats.certificatesIssued++;
    else
        stats.pendingCertificates++;

    stats.remindersSent += reminder;

    if(escalation)
        stats.escalations++;

    stats.trainingPrograms[program] =
        (stats.trainingPrograms[program] || 0) + 1;

}

stats.completionRate =
(
stats.completed /
Math.max(stats.totalPartners,1)
*100
).toFixed(1);

return {

json: stats

};

const s = $json;

const health =
Number(s.completionRate) >= 90
? "🟢 Excellent"
: Number(s.completionRate) >= 70
? "🟡 Good"
: "🔴 Needs Attention";

let trainingRows = "";

for (const [program, count] of Object.entries(s.trainingPrograms)) {

    trainingRows += `
        <tr>
            <td style="padding:8px;border:1px solid #ddd;">${program}</td>
            <td style="padding:8px;border:1px solid #ddd;text-align:center;">${count}</td>
        </tr>
    `;

}

const html = `
<html>

<body style="font-family:Arial;background:#f4f4f4;padding:30px;">

<div style="
background:white;
padding:30px;
border-radius:10px;
max-width:900px;
margin:auto;
">

<h1 style="color:#1f4e79;">
Partner Training Dashboard
</h1>

<p>
Generated:
<b>${new Date().toLocaleString()}</b>
</p>

<h2>Overall KPIs</h2>

<table style="border-collapse:collapse;width:100%;">

<tr><td>Total Partners</td><td><b>${s.totalPartners}</b></td></tr>
<tr><td>Active Trainings</td><td><b>${s.active}</b></td></tr>
<tr><td>Completed Trainings</td><td><b>${s.completed}</b></td></tr>
<tr><td>Overdue Trainings</td><td><b>${s.overdue}</b></td></tr>
<tr><td>Completion Rate</td><td><b>${s.completionRate}%</b></td></tr>
<tr><td>Certificates Issued</td><td><b>${s.certificatesIssued}</b></td></tr>
<tr><td>Pending Certificates</td><td><b>${s.pendingCertificates}</b></td></tr>
<tr><td>Total Reminders</td><td><b>${s.remindersSent}</b></td></tr>
<tr><td>Total Escalations</td><td><b>${s.escalations}</b></td></tr>

</table>

<br>

<h2>Training Programs</h2>

<table style="
width:100%;
border-collapse:collapse;
">

<tr style="background:#1f4e79;color:white;">
<th style="padding:10px;">Program</th>
<th>Partners</th>
</tr>

${trainingRows}

</table>

<br>

<h2>Overall Health</h2>

